mapper.select:
SELECT

FROM admin_user


        AND (
            username LIKE CONCAT('%', #{keyword}, '%')
            OR display_name LIKE CONCAT('%', #{keyword}, '%')
        )


        AND status = #{status}


        AND role = #{role}


ORDER BY created_at DESC, username DESC
LIMIT #{limit}
OFFSET #{offset}

mapper.update:
UPDATE admin_user
SET display_name = #{displayName},
    role = #{role},
    status = #{status},
    updated_at = #{updatedAt}
WHERE username = #{username}

UPDATE admin_user
SET last_login_at = #{lastLoginAt},
    updated_at = #{lastLoginAt}
WHERE username = #{username}
